{"command": "cd /tmp/sv-46bf065755af41aebff55db2dfcef11d/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null | python3 -c "
import json, sys
baseline = json.load(open('baseline-packages.json'))
after = json.load(sys.stdin)
json.dump(after, open('after-cpm-packages.json', 'w'), indent=2)

# Compare
for bp, ap in zip(baseline['projects'], after['projects']):
    proj = bp['path'].split('/')[-1]
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        b_pkgs = {p['id']: p['resolvedVersion'] for p in bf.get('topLevelPackages', [])}
        a_pkgs = {p['id']: p['resolvedVersion'] for p in af.get('topLevelPackages', [])}
        for pkg in sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys()))):
            bv = b_pkgs.get(pkg, 'MISSING')
            av = a_pkgs.get(pkg, 'MISSING')
            status = '✅ Unchanged' if bv == av else f'⚠️ Changed: {bv} → {av}'
            print(f'{proj}: {pkg} {bv} → {av} {status}')
"", "description": "Compare baseline vs post-conversion", "initial_wait": 30}

